import time
import httpx

HEALTH_ENDPOINT = "https://agent-primary.example.com/health"
STANDBY_ENDPOINT = "https://agent-standby.example.com/health"
RTO_BUDGET_SECONDS = 15 * 60   # 15 minutes
POLL_INTERVAL_SECONDS = 15
FAILOVER_THRESHOLD_SECONDS = 60  # trigger failover after 60s confirmed downtime


def check_health(url: str) -> bool:
    try:
        resp = httpx.get(url, timeout=5)
        return resp.status_code == 200
    except Exception:
        return False


def trigger_failover_to_standby():
    # In production: update Route 53 weighted routing policy or ALB target group
    print("Initiating failover to standby region...")


def monitor_and_failover():
    failure_start = None
    while True:
        if check_health(HEALTH_ENDPOINT):
            if failure_start is not None:
                recovery_time = time.time() - failure_start
                print(f"Primary recovered in {recovery_time:.1f}s")
            failure_start = None
        else:
            if failure_start is None:
                failure_start = time.time()
                print(f"Primary unhealthy - starting RTO clock")
            elapsed = time.time() - failure_start
            print(f"Still down: {elapsed:.0f}s elapsed / {RTO_BUDGET_SECONDS}s budget")
            if elapsed >= FAILOVER_THRESHOLD_SECONDS:
                trigger_failover_to_standby()
                break
        time.sleep(POLL_INTERVAL_SECONDS)


if __name__ == "__main__":
    monitor_and_failover()
